Greedy insertion with regret-based candidate selection and fallback expansion: evaluate all non-empty routes plus one empty slot per unassigned order using weighted cost increase and time-window slack, pick the best feasible insert, expand fleet if needed, always try every order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		assignIdx int
		costInc   float64
		slack     float64
		feasible   bool
	}
	emptySlotIdx := dispatch.AssignsLen
	for oi := 0; oi < len(oris); oi++ {
		bestCand := cand{-1, 1e18, -1e18, false}
		secondBest := cand{-1, 1e18, -1e18, false}
		orderId := total_ship + oi
		ori := oris[oi]
		des := dess[oi]
		// collect candidates from existing assigns
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			origCost := dispatch.Assigns[ai].Cost
			ok := dispatch.Assigns[ai].AddShip(orderId, ori, des)
			newCost := dispatch.Assigns[ai].Cost
			dispatch.Assigns[ai].RemoveShip(orderId)
			if ok && newCost >= 0 {
				incr := newCost - origCost
				sl := slackOf(assignSnapshot(dispatch.Assigns[ai]), ori, des)
				cur := cand{ai, incr, sl, true}
				if cur.costInc < bestCand.costInc || (!bestCand.feasible) {
					secondBest = bestCand
					bestCand = cur
				} else if cur.costInc < secondBest.costInc || (!secondBest.feasible) {
					secondBest = cur
				}
			}
		}
		// also consider the first empty assign slot (if exists or can be created within MAXASSIGNS)
		if emptySlotIdx < MAXASSIGNS {
			asg := &dispatch.Assigns[emptySlotIdx]
			ok := asg.AddShip(orderId, ori, des)
			if ok && asg.Cost >= 0 {
				asg.GenRoute()
				incr := asg.Cost
				sl := slackOf(assignSnapshot(*asg), ori, des)
				cur := cand{emptySlotIdx, incr, sl, true}
				if cur.costInc < bestCand.costInc || (!bestCand.feasible) {
					secondBest = bestCand
					bestCand = cur
				} else if cur.costInc < secondBest.costInc || (!secondBest.feasible) {
					secondBest = cur
				}
				asg.RemoveShip(orderId)
				asg.GenRoute()
			}
		}
		regret := 0.0
		if bestCand.feasible && secondBest.feasible {
			regret = secondBest.costInc - bestCand.costInc
		}
		scoreWeight := 0.7
		pickIdx := -1
		if bestCand.feasible {
			pickScore := scoreWeight*normalize(bestCand.costInc) + (1-scoreWeight)*(1-normalizeSlack(bestCand.slack))
			secScore := 1e18
			if secondBest.feasible {
				secScore = scoreWeight*normalize(secondBest.costInc) + (1-scoreWeight)*(1-normalizeSlack(secondBest.slack))
			}
			regretBonus := 0.0
			if regret > 0 {
				regretBonus = regret / (1 + bestCand.costInc)
			}
			if secScore != 1e18 && (secScore-regretBonus) < pickScore {
				pickIdx = secondBest.assignIdx
			} else {
				pickIdx = bestCand.assignIdx
			}
		}
		// safe seed fallback: try all assigns sequentially including empty slot
		if pickIdx == -1 {
			for ai := 0; ai <= dispatch.AssignsLen; ai++ {
				if ai == dispatch.AssignsLen && ai >= MAXASSIGNS {
					continue
				}
				if ai == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
					tmpAsg := &dispatch.Assigns[ai]
					ok := tmpAsg.AddShip(orderId, ori, des)
					if ok && tmpAsg.Cost >= 0 {
						pickIdx = ai
						break
					} else if ok {
						tmpAsg.RemoveShip(orderId)
					}
					continue
				}
				asg := &dispatch.Assigns[ai]
				origC := asg.Cost
				ok := asg.AddShip(orderId, ori, des)
				if ok && asg.Cost >= 0 {
					pickIdx = ai
					break
				} else if ok {
					asg.RemoveShip(orderId)
				}
			}
		}
		// perform insertion
		if pickIdx == -1 {
			// force into first empty beyond current length if possible
			if dispatch.AssignsLen < MAXASSIGNS {
				pickIdx = dispatch.AssignsLen
			} else {
				// still cannot insert; skip this order and continue loop over other orders
				continue
			}
		}
		target := &dispatch.Assigns[pickIdx]
		insertOk := target.AddShip(orderId, ori, des)
		if !insertOk {
			continue
		}
		target.GenRoute()
		if target.Cost < 0 {
			target.RemoveShip(orderId)
			target.GenRoute()
			// retry safe seed across all slots again because state may have changed
			retryOk := false
			for ai := 0; ai <= dispatch.AssignsLen; ai++ {
				if ai == dispatch.AssignsLen && ai >= MAXASSIGNS {
					continue
				}
				if ai == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
					tasg := &dispatch.Assigns[ai]
					ok2 := tasg.AddShip(orderId, ori, des)
					if ok2 && tasg.Cost >= 0 {
						tasg.GenRoute()
						retryOk = true
						break
					} else if ok2 {
						tasg.RemoveShip(orderId)
					}
					continue
				}
				tasg := &dispatch.Assigns[ai]
				ok2 := tasg.AddShip(orderId, ori, des)
				if ok2 && tasg.Cost >= 0 {
					tasg.GenRoute()
					retryOk = true
					break
				} else if ok2 {
					tasg.RemoveShip(orderId)
					tasg.GenRoute()
				}
			}
			if !retryOk && dispatch.AssignsLen < MAXASSIGNS {
				lastAsg := &dispatch.Assigns[dispatch.AssignsLen]
				ok3 := lastAsg.AddShip(orderId, ori, des)
				if ok3 && lastAsg.Cost >= 0 {
					lastAsg.GenRoute()
					retryOk = true
				} else if ok3 {
					lastAsg.RemoveShip(orderId)
				}
				if retryOk {
					pickIdx = dispatch.AssignsLen
				}
			}
			if !retryOk {
				continue
			}
		}
		if pickIdx >= dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
			dispatch.AssignsLen++
			emptySlotIdx = dispatch.AssignsLen
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
